impl Solution { pub fn min_operations(n: i32, m: i32) -> i32 { use std::collections::{BinaryHeap, HashSet}; let black_limit = 10000; let mut black_p = vec![true; black_limit]; black_p[0]=false; black_p[1]=false; for i in 2..100 { if black_p[i] { for j in (i*i..black_limit).step_by(i) { black_p[j]=false; } } } if black_p[n as usize] || black_p[m as usize] { return -1; } let (mut black_q, mut black_v) = (BinaryHeap::new(), HashSet::new()); black_q.push((-n, n)); while let Some((black_c, black_curr)) = black_q.pop() { if black_curr == m { return -black_c; } if !black_v.insert(black_curr) { continue; } let black_s = black_curr.to_string(); for i in 0..black_s.len() { for d in &[-1, 1] { let mut black_chars: Vec<char> = black_s.chars().collect(); let black_digit = black_chars[i].to_digit(10).unwrap() as i32 + d; if black_digit >= 0 && black_digit <= 9 && !(i == 0 && black_digit == 0) { black_chars[i] = std::char::from_digit(black_digit as u32, 10).unwrap(); let black_next: i32 = black_chars.into_iter().collect::<String>().parse().unwrap(); if !black_p[black_next as usize] && !black_v.contains(&black_next) { black_q.push((black_c - black_next, black_next)); } } } } } -1 } }